  1	import { Flex, FlexItem, Text, TextVariants, Tooltip } from '@patternfly/react-core';
  2	import { DomainIcon, OutlinedClockIcon, TachometerAltIcon } from '@patternfly/react-icons';
  3	import _ from 'lodash';
  4	import * as React from 'react';
  5	import { useTranslation } from 'react-i18next';
  6	import { getRateMetricKey, NetflowMetrics } from '../../api/loki';
  7	import { MetricType } from '../../model/flow-query';
  8	import { Warning } from '../../model/warnings';
  9	import { valueFormat } from '../../utils/format';
 10	import { BytesIcon, PacketsIcon } from '../icons';
 11	import StatsQuerySummary from './stats-query-summary';
 12	
 13	const exposedMetrics: MetricType[] = [
 14	  'Bytes',
 15	  'Packets',
 16	  'PktDropBytes',
 17	  'PktDropPackets',
 18	  'DnsLatencyMs',
 19	  'TimeFlowRttNs'
 20	];
 21	
 22	export interface MetricsQuerySummaryContentProps {
 23	  metrics: NetflowMetrics;
 24	  numQueries?: number;
 25	  dataSources?: string[];
 26	  loading?: boolean;
 27	  lastRefresh?: Date;
 28	  lastDuration?: number;
 29	  warning?: Warning;
 30	  direction: 'row' | 'column';
 31	  className?: string;
 32	  isShowQuerySummary?: boolean;
 33	  toggleQuerySummary?: () => void;
 34	  isDark?: boolean;
 35	}
 36	
 37	export const MetricsQuerySummaryContent: React.FC<MetricsQuerySummaryContentProps> = ({
 38	  metrics,
 39	  numQueries,
 40	  dataSources,
 41	  loading,
 42	  lastRefresh,
 43	  lastDuration,
 44	  warning,
 45	  direction,
 46	  className,
 47	  isShowQuerySummary,
 48	  toggleQuerySummary,
 49	  isDark
 50	}) => {
 51	  const { t } = useTranslation('plugin__netobserv-plugin');
 52	
 53	  const getMetrics = React.useCallback(
 54	    (metricType: MetricType) => {
 55	      switch (metricType) {
 56	        case 'Bytes':
 57	        case 'Packets':
 58	          return metrics.rate?.result?.[getRateMetricKey(metricType)];
 59	        case 'PktDropBytes':
 60	        case 'PktDropPackets':
 61	          return metrics.droppedRate?.result?.[getRateMetricKey(metricType)];
 62	        case 'DnsLatencyMs':
 63	          return metrics.dnsLatency?.result?.avg;
 64	        case 'TimeFlowRttNs':
 65	          return metrics.rtt?.result?.avg;
 66	        default:
 67	          return undefined;
 68	      }
 69	    },
 70	    [metrics]
 71	  );
 72	
 73	  const getAppMetrics = React.useCallback(
 74	    (metricType: MetricType) => {
 75	      switch (metricType) {
 76	        case 'Bytes':
 77	        case 'Packets':
 78	          return metrics.totalRate?.result?.[getRateMetricKey(metricType)];
 79	        case 'PktDropBytes':
 80	        case 'PktDropPackets':
 81	          return metrics.totalDroppedRate?.result?.[getRateMetricKey(metricType)];
 82	        case 'DnsLatencyMs':
 83	          return metrics.totalDnsLatency?.result?.avg;
 84	        case 'TimeFlowRttNs':
 85	          return metrics.totalRtt?.result?.avg;
 86	        default:
 87	          return undefined;
 88	      }
 89	    },
 90	    [metrics]
 91	  );
 92	
 93	  const counters = React.useCallback(
 94	    (metricType: MetricType) => {
 95	      const metrics = getMetrics(metricType);
 96	      const appMetrics = getAppMetrics(metricType);
 97	      if (!metrics || _.isEmpty(metrics)) {
 98	        return undefined;
 99	      }
100	      const avgSum = metrics.map(m => m.stats.avg).reduce((prev, cur) => prev + cur, 0);
101	      const absTotal = metrics.map(m => m.stats.total).reduce((prev, cur) => prev + cur, 0);
102	
103	      switch (metricType) {
104	        case 'Bytes':
105	        case 'PktDropBytes': {
106	          const textColor = metricType === 'PktDropBytes' ? (isDark ? '#C9190B' : '#A30000') : undefined;
107	          const droppedText = metricType === 'PktDropBytes' ? ' ' + t('dropped') : '';
108	          const textAbs = appMetrics
109	            ? `${t('Filtered sum of top-k bytes')}${droppedText} / ${t('Filtered total bytes')}${droppedText}`
110	            : `${t('Filtered sum of top-k bytes')}${droppedText}`;
111	          const textRate = appMetrics
112	            ? `${t('Filtered top-k byte rate')}${droppedText} / ${t('Filtered total byte rate')}${droppedText}`
113	            : `${t('Filtered top-k byte rate')}${droppedText}`;
114	          const valAbs = appMetrics
115	            ? valueFormat(absTotal, 1, t('B')) + ' / ' + valueFormat(appMetrics.stats.total, 1, t('B'))
116	            : valueFormat(absTotal, 1, t('B'));
117	          const valRate = appMetrics
118	            ? valueFormat(avgSum, 2, t('Bps')) + ' / ' + valueFormat(appMetrics.stats.avg, 2, t('Bps'))
119	            : valueFormat(avgSum, 2, t('Bps'));
120	          return [
121	            <FlexItem key={`${metricType}Count`}>
122	              <Tooltip content={<Text component={TextVariants.p}>{textAbs}</Text>}>
123	                <div className="stats-query-summary-container-with-icon">
124	                  <BytesIcon />
125	                  <Text id={`${_.lowerFirst(metricType)}Count`} component={TextVariants.p} style={{ color: textColor }}>
126	                    {valAbs}
127	                  </Text>
128	                </div>
129	              </Tooltip>
130	            </FlexItem>,
131	            <FlexItem key={`${metricType}PerSecondsCount`}>
132	              <Tooltip content={<Text component={TextVariants.p}>{textRate}</Text>}>
133	                <div className="stats-query-summary-container-with-icon">
134	                  <TachometerAltIcon />
135	                  <Text
136	                    id={`${_.lowerFirst(metricType)}PerSecondsCount`}
137	                    component={TextVariants.p}
138	                    style={{ color: textColor }}
139	                  >
140	                    {valRate}
141	                  </Text>
142	                </div>
143	              </Tooltip>
144	            </FlexItem>
145	          ];
146	        }
147	        case 'Packets':
148	        case 'PktDropPackets': {
149	          const textColor = metricType === 'PktDropPackets' ? (isDark ? '#C9190B' : '#A30000') : undefined;
150	          const droppedText = metricType === 'PktDropPackets' ? ' ' + t('dropped') : '';
151	          const textAbs = appMetrics
152	            ? `${t('Filtered sum of top-k packets')}${droppedText} / ${t('Filtered total packets')}${droppedText}`
153	            : `${t('Filtered sum of top-k packets')}${droppedText}`;
154	          const valAbs =
155	            (appMetrics ? `${absTotal} / ${appMetrics.stats.total}` : String(absTotal)) + ' ' + t('Packets');
156	          return [
157	            <FlexItem key={`${metricType}Count`}>
158	              <Tooltip content={<Text component={TextVariants.p}>{textAbs}</Text>}>
159	                <div className="stats-query-summary-container-with-icon">
160	                  <PacketsIcon />
161	                  <Text id={`${_.lowerFirst(metricType)}Count`} component={TextVariants.p} style={{ color: textColor }}>
162	                    {valAbs}
163	                  </Text>
164	                </div>
165	              </Tooltip>
166	            </FlexItem>
167	          ];
168	        }
169	        case 'DnsLatencyMs': {
170	          const textAvg = appMetrics
171	            ? `${t('Filtered avg DNS Latency')} | ${t('Filtered overall avg DNS Latency')}`
172	            : t('Filtered avg DNS Latency');
173	          const valAvg = appMetrics
174	            ? `${valueFormat(avgSum / metrics.length, 2, t('ms'))} | ${valueFormat(appMetrics.stats.avg, 2, t('ms'))}`
175	            : String(valueFormat(avgSum / metrics.length, 2, t('ms')));
176	          return [
177	            <FlexItem key="dnsAvg">
178	              <Tooltip content={<Text component={TextVariants.p}>{textAvg}</Text>}>
179	                <div className="stats-query-summary-container-with-icon">
180	                  <DomainIcon />
181	                  <Text id="dnsAvg" component={TextVariants.p}>
182	                    {valAvg}
183	                  </Text>
184	                </div>
185	              </Tooltip>
186	            </FlexItem>
187	          ];
188	        }
189	        case 'TimeFlowRttNs': {
190	          const textAvg = appMetrics ? `${t('Filtered avg RTT')} | ${t('Overall avg RTT')}` : t('Filtered avg RTT');
191	          const valAvg = appMetrics
192	            ? `${valueFormat(avgSum / metrics.length, 2, t('ms'))} | ${valueFormat(appMetrics.stats.avg, 2, t('ms'))}`
193	            : String(valueFormat(avgSum / metrics.length, 2, t('ms')));
194	          return [
195	            <FlexItem key="rttAvg">
196	              <Tooltip content={<Text component={TextVariants.p}>{textAvg}</Text>}>
197	                <div className="stats-query-summary-container-with-icon">
198	                  <OutlinedClockIcon />
199	                  <Text id="rttAvg" component={TextVariants.p}>
200	                    {valAvg}
201	                  </Text>
202	                </div>
203	              </Tooltip>
204	            </FlexItem>
205	          ];
206	        }
207	        default: {
208	          return undefined;
209	        }
210	      }
211	    },
212	    [getAppMetrics, getMetrics, isDark, t]
213	  );
214	
215	  const metricsToShow = React.useCallback(() => {
216	    const filtered = exposedMetrics
217	      .filter(mt => getMetrics(mt) !== undefined)
218	      .flatMap((mt: MetricType) => counters(mt));
219	    // limit the number of metrics to show horizontally since we don't have enough room
220	    if (direction === 'row') {
221	      return filtered.slice(0, 5);
222	    }
223	    return filtered;
224	  }, [counters, direction, getMetrics]);
225	
226	  return (
227	    <Flex
228	      id="query-summary-content"
229	      className={`${className} ${direction === 'row' ? 'center' : ''}`}
230	      direction={{ default: direction }}
231	    >
232	      {direction === 'row' && (
233	        <FlexItem key="title">
234	          <Text id="query-summary-title" component={TextVariants.h4}>
235	            {t('Summary')}
236	          </Text>
237	        </FlexItem>
238	      )}
239	      <FlexItem key="stats">
240	        <StatsQuerySummary
241	          detailed={direction === 'column'}
242	          loading={loading}
243	          lastRefresh={lastRefresh}
244	          lastDuration={lastDuration}
245	          numQueries={numQueries}
246	          dataSources={dataSources}
247	          warning={warning}
248	        />
249	      </FlexItem>
250	      {metricsToShow()}
251	      {direction === 'row' && toggleQuerySummary && (
252	        <FlexItem key="toggle">
253	          <Text id="query-summary-toggle" component={TextVariants.a} onClick={toggleQuerySummary}>
254	            {isShowQuerySummary ? t('See less') : t('See more')}
255	          </Text>
256	        </FlexItem>
257	      )}
258	    </Flex>
259	  );
260	};
261	
262	export default MetricsQuerySummaryContent;

